def balanced(s):
    count = 0
    for char in s:
        if char == '(':
            count += 1
        elif char == ')':
            count -= 1
            if count < 0:
                return False
    return count == 0

# Example edge case: empty string is balanced
assert balanced('') == True, "Empty string should be considered balanced"
